const partBData = [
  { "id": "2281_1b_H_01", "case": "Japan's birth rate has reached record lows while the government’s investment in geriatric hospitals has significantly increased life expectancy. Japan now has one of the oldest populations in the world.", "q": "Identify two reasons why Japan has a high average age.", "ans": ["Record low birth rate", "Increased life expectancy"], "concept": "Inference: 'Geriatric hospitals' is a distractor; the economic reason is the resulting life expectancy." },
  { "id": "2281_1b_H_02", "case": "The Nigerian naira's value dropped sharply against the US dollar. This made Nigerian products such as cocoa and textiles more attractive to foreign buyers, while the cost of imported machinery and equipment rose for local firms.", "q": "Identify two effects of the currency depreciation.", "ans": ["Exports became more attractive (cheaper)", "Cost of imports (machinery) rose"], "concept": "Inference: Recognizing 'domestic products more attractive' as a price effect of depreciation." },
  { "id": "2281_1b_H_03", "case": "Farmers in Australia have switched to using drones to monitor crops across vast fields. This has reduced the need for manual labour but increased the farm's electricity and maintenance bills. Australian agriculture is highly mechanised.", "q": "Identify two changes to the firm's cost structure.", "ans": ["Reduction in labor costs", "Increase in variable/operating costs (electricity/maintenance)"], "concept": "Inference: Identifying factor substitution (Capital for Labor)." },
  { "id": "2281_1b_H_04", "case": "The Central Bank of Turkey made it cheaper for commercial banks to borrow funds by lowering the discount rate. At the same time, it sold its own holdings of government bonds in the open market. Turkey has struggled with high inflation.", "q": "Identify two monetary policy tools used.", "ans": ["Lowering interest rates (Discount rate)", "Open market operations (Selling bonds)"], "concept": "Inference: Translating actions into technical policy terms." },
  { "id": "2281_1b_H_05", "case": "As China's economy grew rapidly, many cities suffered from thick smog and a massive depletion of the local timber supply. The government has since introduced policies to reduce pollution and protect forests.", "q": "Identify two external costs of economic growth.", "ans": ["Air pollution (Smog)", "Depletion of natural resources (Timber)"], "concept": "Inference: Mapping environmental damage to the concept of 'External Costs'." },
  { "id": "2281_1b_H_06", "case": "The merger between the two largest airlines in South Africa led to fewer flights on unpopular routes and a significant increase in ticket prices. The competition authority investigated the merger.", "q": "Identify two disadvantages of the monopoly created.", "ans": ["Reduced choice/supply (fewer flights)", "Higher prices"], "concept": "Inference: Extracting monopoly outcomes from a specific industry case." },
  { "id": "2281_1b_H_07", "case": "Young professionals in India are moving to Mumbai and Bangalore because the manufacturing plants and mills in their hometowns in the north have permanently closed. India is experiencing rapid urbanisation.", "q": "Identify two reasons for the internal migration.", "ans": ["Search for employment (implied)", "Deindustrialization of hometowns"], "concept": "Inference: Identifying 'push' factors." },
  { "id": "2281_1b_H_08", "case": "The German government granted a €2 subsidy per unit to solar panel manufacturers, causing the supply curve to shift to the right. Germany has been a leader in renewable energy policy.", "q": "Identify two ways the government influenced the market.", "ans": ["Provided a subsidy", "Increased the market supply"], "concept": "Inference: Connecting a financial grant to a market outcome." },
  { "id": "2281_1b_H_09", "case": "Inflation in Argentina rose because the trade unions successfully negotiated a 10% pay rise across the economy and the global price of electricity spiked. Argentina has a history of high inflation.", "q": "Identify two causes of inflation mentioned.", "ans": ["Cost-push (pay rise)", "Cost-push (energy prices)"], "concept": "Inference: Classifying types of cost-push inflation." },
  { "id": "2281_1b_H_10", "case": "Consumers in the UAE are buying more luxury cars despite the global recession because their wealth is tied up in rising property prices. The UAE has a large expatriate population with high incomes.", "q": "Identify two factors influencing consumer demand.", "ans": ["Rising property prices (Wealth effect)", "Consumer tastes/preference for luxury"], "concept": "Inference: Identifying the 'Wealth Effect' as a demand driver." },
  { "id": "2281_1b_H_11", "case": "Vietnam's new environmental law prevents firms from dumping chemicals into rivers and mandates a 20% reduction in carbon output by 2030. Vietnam is industrialising rapidly.", "q": "Identify two types of government regulation.", "ans": ["Ban on pollution (dumping)", "Setting environmental standards/quotas"], "concept": "Inference: Categorizing legal mandates." },
  { "id": "2281_1b_H_12", "case": "Brazil's orange harvest was ruined by an unusual frost in 2023, while a new health report from the WHO encouraged millions of consumers to drink more orange juice. Brazil is the world's largest orange producer.", "q": "Identify a supply factor and a demand factor mentioned.", "ans": ["Supply: Weather/Frost", "Demand: Health report/Consumer tastes"], "concept": "Inference: Distinguishing between S and D shifters." },
  { "id": "2281_1b_H_13", "case": "A multinational company built a new factory in Kenya, providing training for 500 local workers, but the construction destroyed a local heritage site. Kenya has attracted FDI in manufacturing.", "q": "Identify a social benefit and a social cost.", "ans": ["Benefit: Training/Education", "Cost: Destruction of heritage site"], "concept": "Inference: Categorizing impacts of foreign investment." },
  { "id": "2281_1b_H_14", "case": "Output per worker at a car factory in South Korea increased because the firm introduced a conveyor belt and offered bonuses for zero-defect production. South Korea is a major exporter of vehicles.", "q": "Identify two ways the firm increased productivity.", "ans": ["Division of labor/Automation (Conveyor belt)", "Financial incentives (Bonuses)"], "concept": "Inference: Linking 'Output per worker' to its causes." },
  { "id": "2281_1b_H_15", "case": "The UK has a deficit on its trade in goods but earns significant profit from its overseas investments and banking services. The City of London is a global financial centre.", "q": "Identify two components of the Current Account mentioned.", "ans": ["Trade in goods (Visible balance)", "Primary income (Profit from investments) or Services"], "concept": "Inference: Mapping 'banking services' to 'Trade in Services'." },
  { "id": "2281_1b_H_16", "case": "The Indian government decided to sell the state-owned airline Air India and remove the price floor on domestic tickets to increase competition. India has been liberalising its aviation sector.", "q": "Identify two supply-side measures aimed at increasing competition.", "ans": ["Privatization", "Deregulation (removing price floor)"], "concept": "Inference: Using economic terminology to describe government actions." },
  { "id": "2281_1b_H_17", "case": "High school graduates in Egypt are struggling to find work because they lack the coding skills required by the modern economy. Egypt has a young population and high youth unemployment.", "q": "Identify two reasons for the unemployment.", "ans": ["Lack of skills (Skill mismatch)", "Technological change"], "concept": "Inference: Identifying 'Structural Unemployment'." },
  { "id": "2281_1b_H_18", "case": "A Malaysian rubber company is expanding by purchasing its main supplier of rubber and its primary shipping company. Malaysia is a major producer of natural rubber.", "q": "Identify two types of vertical integration.", "ans": ["Backward vertical integration (supplier)", "Forward vertical integration (shipping)"], "concept": "Inference: Identifying the direction of integration." },
  { "id": "2281_1b_H_19", "case": "Bulgaria's population is shrinking because more people are moving abroad for work than are arriving, and the death rate has exceeded the birth rate. Bulgaria has one of the fastest-shrinking populations in the EU.", "q": "Identify two reasons for the population decline.", "ans": ["Negative net migration", "Negative natural increase (DR > BR)"], "concept": "Inference: Summarizing demographic trends." },
  { "id": "2281_1b_H_20", "case": "In Pakistan, the regressive tax on bread means the poorest families pay a larger share of their income on food, while the tax-free allowance on income was recently removed. Pakistan has a narrow tax base.", "q": "Identify two changes to the tax system that affect the poor.", "ans": ["Regressive tax on necessities", "Removal of tax-free allowance"], "concept": "Inference: Identifying the burden of taxation." },
  { "id": "2281_1b_H_21", "case": "In Singapore, public goods like streetlights are not provided by private firms because they cannot stop non-payers from using them and one person's use doesn't reduce another's. Singapore invests heavily in public infrastructure.", "q": "Identify two characteristics of public goods.", "ans": ["Non-excludability", "Non-rivalry"], "concept": "Inference: Extracting definitions from an explanation." },
  { "id": "2281_1b_H_22", "case": "The European Central Bank increased the amount of cash commercial banks must keep in their vaults and raised the base lending rate to cool the eurozone economy. Inflation had risen above target.", "q": "Identify two contractionary monetary policies.", "ans": ["Increasing reserve requirements", "Increasing interest rates"], "concept": "Inference: Identifying tools for cooling an economy." },
  { "id": "2281_1b_H_23", "case": "A textile factory in Bangladesh saw its total cost rise because the price of raw cotton doubled, but its fixed cost per unit fell as it produced more. Bangladesh is a major garment exporter.", "q": "Identify a reason for the increase in total cost and a reason for the fall in average fixed cost.", "ans": ["Rise in variable costs (raw materials)", "Increase in output (spreading fixed costs)"], "concept": "Inference: Distinguishing cost behavior." },
  { "id": "2281_1b_H_24", "case": "Greek secondary sector workers are losing jobs as the country specialises in finance and international shipping. Greece has shifted towards services since the financial crisis.", "q": "Identify two tertiary sector industries.", "ans": ["Finance", "International shipping"], "concept": "Inference: Classifying industries by sector." },
  { "id": "2281_1b_H_25", "case": "The Ethiopian government is building new roads and ports to help firms transport goods faster and lower their costs. Ethiopia is landlocked and depends on Djibouti for trade.", "q": "Identify two types of infrastructure investment.", "ans": ["Roads", "Ports"], "concept": "Inference: Identifying physical capital." },
  { "id": "2281_1b_H_26", "case": "In the UK, demand for butter rose because the price of margarine increased and the price of bread fell. The UK has a large dairy industry.", "q": "Identify the relationship between butter and margarine, and butter and bread.", "ans": ["Butter/Margarine: Substitutes", "Butter/Bread: Complements"], "concept": "Inference: Identifying cross-elasticity relationships." },
  { "id": "2281_1b_H_27", "case": "The state-owned railway in France can charge different prices to different customers because it is the only provider on many routes and it can prevent people from reselling tickets. France has a heavily regulated transport sector.", "q": "Identify two conditions for price discrimination.", "ans": ["Monopoly power", "Ability to separate markets (prevent resale)"], "concept": "Inference: Extracting conditions from a scenario." },
  { "id": "2281_1b_H_28", "case": "Economic development in Malawi is low due to a lack of clean water and a high proportion of children not completing primary school. Malawi is one of the poorest countries in Africa.", "q": "Identify two indicators of low economic development.", "ans": ["Lack of clean water (sanitation)", "Low literacy/education levels"], "concept": "Inference: Mapping living standards to development concepts." },
  { "id": "2281_1b_H_29", "case": "The trade union at a factory in Bangladesh called for a strike after the management refused to provide protective clothing or allow for regular breaks. Bangladesh has a large garment sector.", "q": "Identify two working conditions the union wanted to improve.", "ans": ["Safety (protective clothing)", "Health/Rest (regular breaks)"], "concept": "Inference: Identifying non-wage demands." },
  { "id": "2281_1b_H_30", "case": "Hyperinflation in Zimbabwe caused the local currency to become worthless, forcing people to trade goods for other goods instead. Zimbabwe later adopted the US dollar.", "q": "Identify the economic term for 'trading goods for goods' and the reason it happened.", "ans": ["Barter", "Hyperinflation (currency lost its function)"], "concept": "Inference: Identifying barter in a modern context." },
  { "id": "2281_1b_H_31", "case": "Foreign investors are leaving Myanmar because of the high risk of civil conflict and the lack of a stable legal system. Myanmar has seen a sharp fall in FDI in recent years.", "q": "Identify two political/legal factors discouraging FDI.", "ans": ["Political instability (Civil war)", "Lack of rule of law (legal system)"], "concept": "Inference: Identifying investment barriers." },
  { "id": "2281_1b_H_32", "case": "The Norwegian government's subsidy to electric car buyers makes the final price lower than the cost of production. Norway has one of the highest rates of electric car ownership.", "q": "Identify who receives the subsidy and its effect on price.", "ans": ["Consumers (buyers)", "Lower price"], "concept": "Inference: Identifying the beneficiary." },
  { "id": "2281_1b_H_33", "case": "A large retail chain in the USA is experiencing diseconomies of scale as it takes too long for decisions to reach workers and management is losing track of inventory. The firm has expanded rapidly.", "q": "Identify two types of diseconomies of scale.", "ans": ["Communication failure", "Managerial inefficiency"], "concept": "Inference: Categorizing specific internal problems." },
  { "id": "2281_1b_H_34", "case": "The government of Rwanda is trying to reduce the use of plastic bags by charging 10 cents per bag and running advertisements about ocean pollution. Rwanda has banned single-use plastics.", "q": "Identify a fiscal measure and an information-based measure.", "ans": ["Fiscal: Tax/Charge per bag", "Information: Advertising/Education campaign"], "concept": "Inference: Identifying policy types." },
  { "id": "2281_1b_H_35", "case": "In the Democratic Republic of Congo, real GDP per head fell because the population grew by 5% while the economy only grew by 2%. The DRC has a very young and fast-growing population.", "q": "Identify two reasons why the standard of living fell.", "ans": ["High population growth", "Low economic growth"], "concept": "Inference: Linking growth rates to living standards." },
  { "id": "2281_1b_H_36", "case": "In Spain, the supply of labour for fruit picking is low because the work is physically demanding and only available in the summer. Spain relies on seasonal migrant workers for its agriculture.", "q": "Identify two non-wage factors affecting labor supply.", "ans": ["Job difficulty (physically demanding)", "Job security/Seasonality (summer only)"], "concept": "Inference: Identifying labor shifters." },
  { "id": "2281_1b_H_37", "case": "MNCs in Vietnam pay higher wages than local firms, but they often source their raw materials from abroad. Vietnam has attracted much FDI in electronics manufacturing.", "q": "Identify one benefit and one drawback of MNCs.", "ans": ["Benefit: Higher wages", "Drawback: Leakage from the economy (importing materials)"], "concept": "Inference: Identifying domestic impacts of MNCs." },
  { "id": "2281_1b_H_38", "case": "Niger's birth rate is high because children are needed for labour on family farms and there is a lack of social security for the elderly. Niger has one of the highest birth rates in the world.", "q": "Identify two economic reasons for a high birth rate.", "ans": ["Children as a source of labor", "Lack of state pensions/support"], "concept": "Inference: Identifying drivers of population growth." },
  { "id": "2281_1b_H_39", "case": "Switzerland's trade surplus grew as the country began exporting more high-tech medical equipment and importing fewer luxury watches. Switzerland has a highly specialised export base.", "q": "Identify two changes to the balance of trade.", "ans": ["Increased export revenue", "Decreased import expenditure"], "concept": "Inference: Identifying flows." },
  { "id": "2281_1b_H_40", "case": "A public limited company in the UK is different from a private one because it must publish its accounts and anyone can buy its shares on the stock exchange. Many UK firms have listed on the London Stock Exchange.", "q": "Identify two features of a public limited company.", "ans": ["Transparency (publish accounts)", "Publicly traded shares"], "concept": "Inference: Identifying legal requirements." },
  { "id": "2281_1b_H_41", "case": "Devaluation of the Egyptian pound will likely lead to demand-pull inflation as exports rise and cost-push inflation as oil imports become expensive. Egypt imports most of its energy.", "q": "Identify two types of inflation caused by devaluation.", "ans": ["Demand-pull", "Cost-push"], "concept": "Inference: Categorizing inflationary pressures." },
  { "id": "2281_1b_H_42", "case": "Structural unemployment in the UK steel industry is high because of competition from cheaper foreign imports and the shift toward lighter materials like aluminium. Many steel towns have declined.", "q": "Identify two causes of structural unemployment.", "ans": ["Foreign competition", "Changes in consumer demand (substitute materials)"], "concept": "Inference: Identifying industry decline factors." },
  { "id": "2281_1b_H_43", "case": "The Italian government is using a contractionary fiscal policy to reduce the national debt by raising the VAT rate and cutting the defence budget. Italy has one of the highest debt ratios in the eurozone.", "q": "Identify two fiscal measures used.", "ans": ["Raising indirect tax (VAT)", "Cutting government spending (defense)"], "concept": "Inference: Identifying policy instruments." },
  { "id": "2281_1b_H_44", "case": "Productivity in Tanzania's manufacturing sector is low because the machines are old and workers frequently take time off due to poor health. Tanzania is trying to industrialise.", "q": "Identify two reasons for low productivity.", "ans": ["Old capital (machinery)", "Low quality of labor (health)"], "concept": "Inference: Identifying factors of production quality." },
  { "id": "2281_1b_H_45", "case": "The primary sector’s share of GDP in Thailand is falling as the country builds more factories and more people work in hotels. Thailand has developed a large tourism industry.", "q": "Identify the sectors the country is moving towards.", "ans": ["Secondary (factories)", "Tertiary (hotels)"], "concept": "Inference: Identifying structural change." },
  { "id": "2281_1b_H_46", "case": "Uganda's specialisation in coffee allows for higher output but leaves the country at risk if the global coffee price collapses. Coffee is Uganda's main export.", "q": "Identify an advantage and a risk of specialization.", "ans": ["Advantage: Higher output/efficiency", "Risk: Over-dependence on one product"], "concept": "Inference: Identifying trade-offs." },
  { "id": "2281_1b_H_47", "case": "In the UK, price elasticity of demand for cigarettes is low because they are addictive and have no close substitutes. The government has raised tobacco taxes to reduce smoking.", "q": "Identify two reasons why PED for cigarettes is inelastic.", "ans": ["Addictive nature", "Lack of substitutes"], "concept": "Inference: Identifying determinants of PED." },
  { "id": "2281_1b_H_48", "case": "The Central Bank of Nigeria maintains the stability of the financial system by regulating commercial banks and controlling the money supply. Nigeria has Africa's largest economy.", "q": "Identify two functions of the Central Bank.", "ans": ["Regulation of banks", "Monetary policy (controlling money supply)"], "concept": "Inference: Identifying roles." },
  { "id": "2281_1b_H_49", "case": "Economic growth in South Africa has slowed because of a lack of skilled workers and the country’s ageing infrastructure. South Africa faces an electricity crisis.", "q": "Identify two supply-side constraints on growth.", "ans": ["Human capital shortage (skills)", "Physical capital decay (infrastructure)"], "concept": "Inference: Identifying limits to growth." },
  { "id": "2281_1b_H_50", "case": "Privatisation of British Rail led to more frequent trains but higher fares for commuters. The UK railway network was split into multiple private operators.", "q": "Identify one positive and one negative outcome of privatization.", "ans": ["Positive: Improved service (more frequent)", "Negative: Higher prices (fares)"], "concept": "Inference: Identifying outcomes for stakeholders." },
  { "id": "2281_1b_H_51", "case": "The Hungarian government is trying to encourage birth rates by offering free childcare and longer paid maternity leave. Hungary has one of the lowest birth rates in the EU.", "q": "Identify two incentives for having children.", "ans": ["Free childcare", "Paid maternity leave"], "concept": "Inference: Identifying demographic policy." },
  { "id": "2281_1b_H_52", "case": "In a market economy, what to produce is decided by consumers through the price mechanism, and competition keeps prices low. The USA is often cited as an example.", "q": "Identify two features of a market economy.", "ans": ["Consumer sovereignty", "Competition"], "concept": "Inference: Identifying system traits." },
  { "id": "2281_1b_H_53", "case": "A South Korean steel company is enjoying purchasing economies of scale as it gets discounts for buying thousands of tons of steel at once. South Korea is a major steel producer.", "q": "Identify the type of economy of scale and the reason for it.", "ans": ["Purchasing (Bulk-buying)", "Discounts on large orders"], "concept": "Inference: Identifying specific internal economies." },
  { "id": "2281_1b_H_54", "case": "The current account deficit narrowed as the tourism sector boomed and people received more money from relatives working abroad. The Philippines receives large remittances from overseas workers.", "q": "Identify two invisible components of the Current Account.", "ans": ["Trade in Services (Tourism)", "Secondary Income (Remittances)"], "concept": "Inference: Mapping terms to invisible categories." },
  { "id": "2281_1b_H_55", "case": "A toy manufacturer in China has high fixed costs like the lease on the factory but low variable costs like the plastic used for each toy. China is the world's largest toy exporter.", "q": "Identify an example of a fixed cost and a variable cost.", "ans": ["Fixed: Lease/Rent", "Variable: Raw materials (plastic)"], "concept": "Inference: Classifying costs." },
  { "id": "2281_1b_H_56", "case": "Demand for labour in Spain's hospitality industry is seasonal, peaking during the summer holidays. Spain attracts millions of tourists each year.", "q": "Identify the type of unemployment that occurs in winter.", "ans": ["Seasonal unemployment"], "concept": "Inference: Identifying unemployment by time of year." },
  { "id": "2281_1b_H_57", "case": "A progressive tax on income can reduce the incentive to work, but it helps the government provide welfare to the unemployed.", "q": "Identify a disadvantage and an advantage of progressive taxation.", "ans": ["Disadvantage: Reduced work incentive", "Advantage: Redistribution of income"], "concept": "Inference: Identifying fiscal trade-offs." },
  { "id": "2281_1b_H_58", "case": "Money serves as a unit of account, allowing consumers to easily compare the prices of different brands of mobile phones.", "q": "Identify the function of money described and the benefit it provides.", "ans": ["Unit of account", "Enables price comparison"], "concept": "Inference: Identifying money functions." },
  { "id": "2281_1b_H_59", "case": "India uses protectionism to prevent foreign firms from selling goods below their cost of production to destroy local competitors. This practice is known as dumping.", "q": "Identify the practice being prevented and the policy used.", "ans": ["Dumping", "Protectionism"], "concept": "Inference: Identifying trade terms." },
  { "id": "2281_1b_H_60", "case": "A monopoly can achieve lower average costs than small firms by investing in expensive but highly efficient technology.", "q": "Identify a reason why monopolies can be more efficient.", "ans": ["Financial economies of scale", "Investment in technology"], "concept": "Inference: Identifying scale advantages." },
  { "id": "2281_1b_H_61", "case": "Capital includes man-made resources like the computers and desks used in an office.", "q": "Identify two examples of the factor of production 'capital'.", "ans": ["Computers", "Desks"], "concept": "Inference: Identifying specific capital assets." },
  { "id": "2281_1b_H_62", "case": "A shortage in Hong Kong's housing market occurs when the price is kept below the equilibrium, leading to a long waiting list for apartments. Hong Kong has expensive housing.", "q": "Identify the policy that causes this and the result.", "ans": ["Price ceiling (Maximum price)", "Market shortage"], "concept": "Inference: Identifying price control outcomes." },
  { "id": "2281_1b_H_63", "case": "Labour productivity on a farm in Zambia rose because the owner started using fertilisers and trained the workers to use tractors. Zambia's agriculture is modernising.", "q": "Identify two ways productivity was improved.", "ans": ["Better raw materials (fertilizers)", "Training (improved human capital)"], "concept": "Inference: Identifying productivity drivers." },
  { "id": "2281_1b_H_64", "case": "Greece's budget deficit is large because the government is building three new hospitals and the economy is in a recession, reducing tax intake. Greece has struggled with high debt.", "q": "Identify two reasons for the budget deficit.", "ans": ["Increased government spending", "Reduced tax revenue"], "concept": "Inference: Identifying fiscal drivers." },
  { "id": "2281_1b_H_65", "case": "Kenya has a high dependency ratio because of a high birth rate and a rising life expectancy. Kenya has a young population.", "q": "Identify the two groups that make up the dependent population.", "ans": ["Children", "Elderly"], "concept": "Inference: Identifying dependency components." },
  { "id": "2281_1b_H_66", "case": "Demand for labour in Germany's car manufacturing fell because firms replaced workers with robotic arms. Germany is a major car producer.", "q": "Identify the cause of the decrease in labor demand and one likely consequence.", "ans": ["Capital-labor substitution (Automation)", "Rise in unemployment / Job losses"], "concept": "Inference: Identifying technological impact on labor." },
  { "id": "2281_1b_H_67", "case": "Specialization leads to boredom for workers as they repeat the same simple task all day, which can actually lower productivity.", "q": "Identify two disadvantages of specialization for workers.", "ans": ["Job dissatisfaction (Boredom)", "Lower productivity"], "concept": "Inference: Identifying human cost of specialization." },
  { "id": "2281_1b_H_68", "case": "The informal sector is large in Peru because many people are self-employed in street vending and their income is not reported. Peru has a large informal economy.", "q": "Identify two features of the informal sector.", "ans": ["Self-employment", "Unrecorded income"], "concept": "Inference: Identifying features of unrecorded GDP." },
  { "id": "2281_1b_H_69", "case": "Foreign aid can help a country build schools, but it can also lead to an increase in national debt if it is provided as a loan.", "q": "Identify one benefit and one risk of foreign aid.", "ans": ["Benefit: Improved education (building schools)", "Risk: Increased debt"], "concept": "Inference: Identifying development trade-offs." },
  { "id": "2281_1b_H_70", "case": "Firms in a perfectly competitive market have no power to set prices because there are many sellers and the products are identical.", "q": "Identify two characteristics of perfect competition.", "ans": ["Many sellers", "Homogeneous products"], "concept": "Inference: Identifying market structure." },
  { "id": "2281_1b_H_71", "case": "A fall in interest rates makes it cheaper for firms to expand their factories and for consumers to buy cars on credit.", "q": "Identify how a fall in interest rates affects investment and consumption.", "ans": ["Increased investment", "Increased consumption"], "concept": "Inference: Identifying interest rate sensitivity." },
  { "id": "2281_1b_H_72", "case": "Supply of unskilled labor is high because no special training is needed, but the wages are kept low by the abundance of applicants.", "q": "Identify the reason for high supply and low wages.", "ans": ["Low entry requirements", "High competition for jobs"], "concept": "Inference: Identifying labor market dynamics." },
  { "id": "2281_1b_H_73", "case": "Trade protectionism helps protect 'infant industries' until they are large enough to compete globally.", "q": "Identify the type of industry being protected and the argument used.", "ans": ["Infant (New) industries", "Needs time to grow / compete globally"], "concept": "Inference: Identifying protectionist arguments." },
  { "id": "2281_1b_H_74", "case": "The current account deficit improved as the currency depreciated, making exports cheaper for foreign buyers.", "q": "Identify the cause and the effect of the improvement in the trade balance.", "ans": ["Currency depreciation", "Exports became cheaper / more competitive"], "concept": "Inference: Identifying exchange rate impact on trade." },
  { "id": "2281_1b_H_75", "case": "Privatization can lead to a more efficient use of resources because firms are motivated by the need to make a profit.", "q": "Identify the main incentive for efficiency and its result.", "ans": ["Profit motive", "More efficient resource use"], "concept": "Inference: Identifying business goals." },
  { "id": "2281_1b_H_76", "case": "An aging population increases the government’s spending on pensions and places a strain on the healthcare system.", "q": "Identify two fiscal impacts of an aging population.", "ans": ["Increased pension spending", "Increased healthcare costs"], "concept": "Inference: Identifying budget pressures." },
  { "id": "2281_1b_H_77", "case": "The production of steel in Poland causes heavy air pollution, which is a cost not paid for by the firm but by local residents who get sick. Poland has large steel plants.", "q": "Identify the economic term for this cost and who pays it.", "ans": ["External cost", "Local residents (Third parties)"], "concept": "Inference: Identifying externalities." },
  { "id": "2281_1b_H_78", "case": "Division of labor means each worker specializes in one part of the assembly line, which speeds up the whole process.", "q": "Identify the economic concept and its main advantage.", "ans": ["Division of labor", "Increased speed/efficiency"], "concept": "Inference: Identifying production concepts." },
  { "id": "2281_1b_H_79", "case": "Consumer spending on necessities like salt is unlikely to change much even if the price increases significantly.", "q": "Identify the type of demand elasticity and an example from the case.", "ans": ["Price inelastic demand", "Necessities / Salt"], "concept": "Inference: Identifying elasticity types." },
  { "id": "2281_1b_H_80", "case": "The government is trying to reduce regional inequality by providing grants to firms that set up factories in poorer areas.", "q": "Identify the policy aim and the tool used.", "ans": ["Reduce regional inequality", "Subsidies (Grants)"], "concept": "Inference: Identifying regional policy." },
  { "id": "2281_1b_H_81", "case": "A firm's profit is the difference between the total revenue it earns from sales and its total costs.", "q": "Identify the formula for profit.", "ans": ["TR - TC"], "concept": "Inference: Identifying definitions." },
  { "id": "2281_1b_H_82", "case": "Floating exchange rates can be volatile, making it difficult for firms to plan their future import and export costs.", "q": "Identify two disadvantages of a floating exchange rate.", "ans": ["Uncertainty (Volatility)", "Difficulty planning import/export costs"], "concept": "Inference: Identifying currency risks." },
  { "id": "2281_1b_H_83", "case": "A firm can expand internally by reinvesting its profits into new machinery and hiring more workers.", "q": "Identify two methods of internal (organic) growth.", "ans": ["Investing in capital", "Hiring more labor"], "concept": "Inference: Identifying growth types." },
  { "id": "2281_1b_H_84", "case": "MNCs can benefit a host country by paying taxes to the local government and sharing their technical knowledge with local firms.", "q": "Identify two benefits of MNCs.", "ans": ["Tax revenue", "Technology transfer"], "concept": "Inference: Identifying spillover effects." },
  { "id": "2281_1b_H_85", "case": "The central bank keeps inflation low to prevent the value of people's savings from being eroded over time.", "q": "Identify a goal of monetary policy and the reason for it.", "ans": ["Price stability (low inflation)", "Protect value of savings"], "concept": "Inference: Identifying policy objectives." },
  { "id": "2281_1b_H_86", "case": "Supply of agricultural products is often unstable because it is affected by unpredictable weather conditions and pests.", "q": "Identify two factors that make agricultural supply volatile.", "ans": ["Weather", "Pests"], "concept": "Inference: Identifying supply shocks." },
  { "id": "2281_1b_H_87", "case": "The tertiary sector is the largest part of the economy in developed countries, including banking, education and tourism.", "q": "Identify two tertiary industries mentioned.", "ans": ["Banking", "Education (or Tourism)"], "concept": "Inference: Classifying industries." },
  { "id": "2281_1b_H_88", "case": "A country has a comparative advantage in textiles because it has an abundance of cheap labor and cotton.", "q": "Identify two reasons for the comparative advantage.", "ans": ["Cheap labor", "Availability of raw materials (cotton)"], "concept": "Inference: Identifying sources of advantage." },
  { "id": "2281_1b_H_89", "case": "Monopolies might charge high prices, but they can also use their large profits to fund expensive research and development.", "q": "Identify an advantage and a disadvantage of a monopoly.", "ans": ["Advantage: R&D/Innovation", "Disadvantage: High prices"], "concept": "Inference: Identifying monopoly trade-offs." },
  { "id": "2281_1b_H_90", "case": "The government is increasing the school-leaving age to 18 to ensure a more skilled labor force in the future.", "q": "Identify the supply-side policy and its intended impact.", "ans": ["Education reform (increasing school age)", "Improved labor quality/skills"], "concept": "Inference: Identifying human capital policy." },
  { "id": "2281_1b_H_91", "case": "Inflation is often measured by a consumer price index, which tracks the price of a 'basket' of goods over time.", "q": "Identify the tool used to measure inflation and what it tracks.", "ans": ["Consumer Price Index (CPI)", "Price of a basket of goods"], "concept": "Inference: Identifying inflation measurement." },
  { "id": "2281_1b_H_92", "case": "Foreign workers often move to countries with a higher standard of living and better job opportunities in the service sector.", "q": "Identify two reasons for international migration.", "ans": ["Higher standard of living", "Better job opportunities"], "concept": "Inference: Identifying pull factors." },
  { "id": "2281_1b_H_93", "case": "The price of wheat in international markets rose because of a global drought and an increase in the demand for bread. Wheat is a staple food in many countries.", "q": "Identify a supply-side and a demand-side reason for the price rise.", "ans": ["Supply: Drought", "Demand: Increased demand for bread"], "concept": "Inference: Identifying price determinants." },
  { "id": "2281_1b_H_94", "case": "A firm's average cost falls as it produces more because its fixed costs are spread over a larger number of units.", "q": "Identify the relationship between output and average fixed cost, and the reason for it.", "ans": ["Inverse relationship (AFC falls as output rises)", "Fixed costs spread over more units"], "concept": "Inference: Identifying cost behavior." },
  { "id": "2281_1b_H_95", "case": "Public corporations are often inefficient because they are not motivated by profit and are protected from competition.", "q": "Identify two reasons for inefficiency in the public sector.", "ans": ["Lack of profit motive", "Lack of competition"], "concept": "Inference: Identifying public sector challenges." },
  { "id": "2281_1b_H_96", "case": "The primary sector involves the extraction of natural resources, such as coal mining and oil drilling.", "q": "Identify two examples of primary sector activities.", "ans": ["Coal mining", "Oil drilling"], "concept": "Inference: Identifying specific sector activities." },
  { "id": "2281_1b_H_97", "case": "A high birth rate can be a burden on the economy as it requires high spending on schools and hospitals for children.", "q": "Identify two fiscal impacts of a high birth rate.", "ans": ["Increased spending on education", "Increased spending on healthcare"], "concept": "Inference: Identifying budget pressures." },
  { "id": "2281_1b_H_98", "case": "Fixed costs must be paid even if the firm produces nothing, such as the interest on a bank loan.", "q": "Identify a feature and an example of fixed costs.", "ans": ["Feature: Paid at zero output", "Example: Interest on loans"], "concept": "Inference: Identifying cost traits." },
  { "id": "2281_1b_H_99", "case": "The price of luxury goods is very sensitive to changes in income, meaning they have a high income elasticity of demand.", "q": "Identify the type of elasticity and the sensitivity described.", "ans": ["High Income Elasticity", "Sensitive to income changes"], "concept": "Inference: Identifying YED." },
  { "id": "2281_1b_H_100", "case": "The government is trying to improve the environment by taxing polluting factories and subsidizing renewable energy.", "q": "Identify two fiscal measures used to improve the environment.", "ans": ["Pollution tax", "Subsidies for green energy"], "concept": "Inference: Identifying environmental policy." },
  { "id": "2281_1b_H_101", "case": "Education and vaccinations are under-consumed because people do not consider their full benefits to society.", "q": "Identify two characteristics of merit goods.", "ans": ["Under-consumed", "External benefits or social benefits"], "concept": "Inference: Market failure – merit goods." },
  { "id": "2281_1b_H_102", "case": "Alcohol is over-consumed because consumers ignore the harm it causes to others through accidents and healthcare costs.", "q": "Identify two characteristics of demerit goods.", "ans": ["Over-consumed", "External costs or social costs"], "concept": "Inference: Market failure – demerit goods." },
  { "id": "2281_1b_H_103", "case": "Coal miners in Wales struggle to find work as mines close because they lack skills for new industries and cannot afford to move to other regions. The UK coal industry has declined.", "q": "Identify two types of factor immobility.", "ans": ["Occupational immobility", "Geographical immobility"], "concept": "Inference: Factor immobility as cause of market failure." },
  { "id": "2281_1b_H_104", "case": "In the UK, two rival supermarkets merged into one chain, and a car manufacturer bought a hotel group. Both mergers required competition authority approval.", "q": "Identify the two types of mergers described.", "ans": ["Horizontal merger (supermarkets)", "Conglomerate merger (car and hotel)"], "concept": "Inference: Mergers – horizontal vs conglomerate." },
  { "id": "2281_1b_H_105", "case": "A family bakery in France employs 5 workers and competes with large supermarket chains. France has a strong tradition of small artisanal businesses.", "q": "Identify two advantages of small firms.", "ans": ["Personal service / Customer loyalty", "Flexibility / Quick decision-making"], "concept": "Inference: Small firms – syllabus 3.5.2." },
  { "id": "2281_1b_H_106", "case": "Some firms aim to maximise profit; others prioritise reducing their environmental impact or expanding market share.", "q": "Identify two possible objectives of firms.", "ans": ["Profit maximisation", "Growth"], "concept": "Inference: Firm objectives. Syllabus 3.7.5: survival, social welfare, profit maximisation, growth." },
  { "id": "2281_1b_H_107", "case": "The UK government cut spending to reduce inflation, but unemployment rose. Export growth worsened the trade deficit. This illustrates conflicts between macroeconomic aims.", "q": "Identify two possible conflicts between macroeconomic aims.", "ans": ["Employment vs price stability", "Economic growth vs balance of payments stability"], "concept": "Inference: Macro aim conflicts – syllabus 4.2.2." },
  { "id": "2281_1b_H_108", "case": "Absolute poverty is measured by a fixed threshold such as living on less than $1.90 a day.", "q": "Identify two features of absolute poverty.", "ans": ["Fixed threshold", "Unable to meet basic needs"], "concept": "Inference: Absolute poverty. Syllabus 5.2.1." },
  { "id": "2281_1b_H_109", "case": "Russia banned all imports from certain Western countries following the political dispute. An embargo is a complete ban on trade.", "q": "Identify the protection method used and one possible reason.", "ans": ["Embargo", "Political reasons / Protect domestic industry"], "concept": "Inference: Embargo – syllabus 6.2.4." },
  { "id": "2281_1b_H_110", "case": "The central bank of Saudi Arabia keeps the local currency (riyal) fixed at $1 = 3.75 riyals against the US dollar. Saudi Arabia has a fixed exchange rate.", "q": "Identify two features of a fixed exchange rate system.", "ans": ["Central bank intervention", "Stable rate"], "concept": "Inference: Fixed exchange rate. Syllabus 6.3.5." },
  { "id": "2281_1b_H_111", "case": "Commercial banks in Kenya accept deposits from the public and lend money to businesses and households. Kenya's banking sector has grown in recent years.", "q": "Identify two functions of commercial banks.", "ans": ["Accept deposits", "Lending"], "concept": "Inference: Commercial banks. Syllabus 3.1.2." },
  { "id": "2281_1b_H_112", "case": "In Ethiopia, agricultural supply is hard to increase quickly; a factory can raise output within weeks using spare capacity. Ethiopia's economy is still largely agricultural.", "q": "Identify two factors affecting price elasticity of supply.", "ans": ["Time period", "Spare capacity"], "concept": "Inference: PES determinants. Syllabus 2.8.3." },

  /* --- Past paper Q1(b) - Identify two --- */
  { "id": "2281_1b_PP_SP20_1b", "case": "Kenya fact file 2015: unemployment rate 10%. In 2015 the Kenyan shilling depreciated from KES88 to KES98 = $1. The interest rate rose to 16.5%. GDP increased.", "q": "Identify two reasons why the total amount saved in Kenya is likely to have increased in 2015.", "ans": ["Higher income / real GDP per head", "Higher interest rate"], "concept": "0455 Specimen 2020 1(b). MS: Higher income (1), higher interest rate (1)." },
  { "id": "2281_1b_PP_w23_22_1b", "case": "More than half of Honduran exports go to the US and 40% of imports come from the US. A high number of Hondurans work in the US and send money back. A successful clothes industry has the potential to reduce poverty.", "q": "Identify two benefits the Honduran economy could gain from a growth in the US economy.", "ans": ["More export demand / more exports to US", "More remittances / more money from workers abroad"], "concept": "0455 w23 variant 22 (Honduras) 1(b). From extract: US trade partner, remittances." },
  { "id": "2281_1b_PP_w23_23_1b", "case": "Montenegro's banks now have more computers, more workers and more office buildings. All commercial banking, telecommunications and aluminium production has been transferred to the private sector.", "q": "Identify two examples of capital goods in Montenegro.", "ans": ["Computers", "Office buildings"], "concept": "0455 w23 variant 23 (Montenegro) 1(b). MS: Computers (1), office buildings (1)." },
  { "id": "2281_1b_PP_w23_21_1b", "case": "Many firms in Cambridge operate in education, healthcare, research and development, and hi-tech manufacturing industries. Cambridge firms' exports are highly knowledge-intensive.", "q": "Identify two types of industries in Cambridge that operate in the tertiary sector.", "ans": ["Education / educational", "Healthcare / health / research / researcher / hi-tech / manufacturing"], "concept": "0455 w23 variant 21 (Cambridge) 1(b). Two from: education, healthcare, R&D, hi-tech." },
  { "id": "2281_1b_PP_s22_21_1b", "case": "Cyprus had a relatively high HDI ranking in 2019. It exports fruit, pharmaceuticals and clothing. Life expectancy rose from 79 to 81 years between 2015 and 2019.", "q": "Identify two indicators of living standards.", "ans": ["GDP per head / per capita / HDI", "Life expectancy / education / qualifications"], "concept": "0455 s22 variant 21 (Cyprus) 1(b). MS: GDP per head, HDI, life expectancy, primary sector, education. Do not reward GDP alone." },
  { "id": "2281_1b_PP_s22_22_1b", "case": "The World Happiness Index ranks countries by life expectancy, freedom, social support, trust, generosity and GDP per head. The Human Development Index also uses similar measures. New Zealand was ranked 8th in the World Happiness Index in 2019.", "q": "Identify two indicators that are in both the World Happiness Index and the Human Development Index.", "ans": ["Life expectancy / GDP per head", "Education / literacy / freedom"], "concept": "0455 s22 variant 22 (Bhutan) 1(b). Both indices use life expectancy, education, income." },
  { "id": "2281_1b_PP_s22_23_1b", "case": "eSports demand has increased because of increases in incomes and decreases in the price of the technology needed to play or watch eSports. A change in social attitudes has also increased female participation.", "q": "Identify two conditions of demand for eSports.", "ans": ["Increase in incomes / higher income", "Decrease in price of technology / cheaper technology"], "concept": "0455 s22 variant 23 (Malta) 1(b). Conditions: income, price of tech, social attitudes." },
  { "id": "2281_1b_PP_s23_21_1b", "case": "Global demand for coal has declined as countries switched to gas, offshore wind and solar power. Australia is a major producer of coal.", "q": "Identify two substitutes for coal.", "ans": ["Gas", "Offshore wind / wind power / solar power"], "concept": "0455 s23 variant 21 (Australia) 1(b). MS: gas, offshore wind, solar power." },
  { "id": "2281_1b_PP_m23_22_1b", "case": "Between 2009 and 2019, US real GDP increased every year. This was the result of low interest rates, land reclamation and an increase in the labour force. The higher output brought benefits but some workers lost their jobs.", "q": "Identify two causes of the increase in the quantity of US factors of production.", "ans": ["Land reclamation / more land / low interest rates", "Increase in labour force / more workers"], "concept": "0455 m23 variant 22 (US) 1(b). MS: low interest rates, land reclamation, labour force increase. Two from." },
  { "id": "2281_1b_PP_s24_21_1b", "case": "Nicaragua has a large agricultural sector. Wages are particularly low in rural areas. The number of Nicaraguans willing and able to work but unable to find a job increased in 2020.", "q": "Identify two rewards to factors of production in Nicaragua.", "ans": ["Wages / labour", "Profits"], "concept": "0455 s24 variant 21 (Nicaragua) 1(b). MS: Wages (1), profits (1). Only these if within first three listed." },
  { "id": "2281_1b_PP_w21_21_1b", "case": "The financial sector, including commercial banks, is growing in Laos. This has enabled local entrepreneurs to borrow money and encouraged more households to save.", "q": "Identify two roles of commercial banks.", "ans": ["Help entrepreneurs borrow / lending / loans", "Encourage households to save / accept deposits"], "concept": "0455 w21 variant 21 (Laos) 1(b). MS: Helps local entrepreneurs borrow (1), encourages households to save (1)." },
  { "id": "2281_1b_PP_w22_21_1b", "case": "The economy of Mauritius has grown. The growth increased income per head and improved healthcare. Life expectancy has increased and the infant mortality rate has fallen significantly.", "q": "Identify two indicators of improving healthcare in Mauritius.", "ans": ["Life expectancy (increased)", "Infant mortality rate (fallen)"], "concept": "0455 w22 variant 21 (Mauritius) 1(b). From extract." },
  { "id": "2281_1b_PP_s20_21_1b", "case": "Vietnamese children have performed better in international tests than children in richer countries. Table 1 shows education spending and labour force in the tertiary sector. Wages and pensions have risen.", "q": "Identify two rewards to factors of production.", "ans": ["Wages / labour / pensions", "Profit / interest / rent"], "concept": "0455 s20 variant 21 (Vietnam) 1(b). MS: wages, pensions, profits." },
  { "id": "2281_1b_PP_w24_21_1b", "case": "The number of foreign nationals living in the UAE is higher than the number of citizens. Labour mobility between the UAE and other countries is high, with many daily flights from India and Pakistan. The UAE hosted the World Expo in 2021–2022.", "q": "Identify two features of globalisation.", "ans": ["Labour mobility / migration / movement of workers", "Increased trade / transport / international links"], "concept": "0455 w24 variant 21 (UAE) 1(b). MS: trade, capital flows, migration, transport." },
  { "id": "2281_1b_PP_s24_22_1b", "case": "The Tunisian government regulates the price of flour and milk. Government control of these prices can help reduce poverty and prevent monopoly firms exploiting their market power. The government also subsidises electricity production.", "q": "Identify two qualities of a good tax.", "ans": ["Cheap to collect / low administrative cost", "Equitable / fair / ability to pay"], "concept": "0455 s24 variant 22 (Tunisia) 1(b). MS: certain, convenient, equitable, cheap to collect." },

  /* --- Past paper Q1(c) - Identify two (Part B style) --- */
  { "id": "2281_1b_PP_w23_21", "case": "Cambridge ranks number one amongst all UK cities in terms of the percentage of workers with a university qualification. Cambridge firms' exports are highly knowledge-intensive, making them highly priced and price-inelastic in demand. Increasing global incomes have also increased the demand for services such as education from Cambridge.", "q": "Identify two benefits of having highly knowledge-intensive exports.", "ans": ["Higher prices / premium pricing / price-inelastic demand", "Demand rises when global incomes rise"], "concept": "0455 w23 variant 21 (Cambridge) 1(c)." },
  { "id": "2281_1b_PP_w22_21", "case": "The economy of Mauritius has grown since it changed from an economy based on the primary sector to one based on the tertiary sector. The growth not only increased income per head but also improved healthcare in Mauritius. Life expectancy has increased and the infant mortality rate (number of infant deaths per thousand births) has fallen significantly.", "q": "Identify two indicators of improving healthcare in Mauritius.", "ans": ["Life expectancy (increased)", "Infant mortality rate (fallen)"], "concept": "0455 w22 variant 21 (Mauritius) 1(c)." },

  /* === Syllabus 0455/2281 2025-26 – Section B (a) / 1(b) style – Identify two from source === */
  { "id": "2281_1b_S25_01", "case": "Zambia has limited land and labour. A choice was made to use more land for maize and less for cotton. The production possibility curve shows the maximum output of maize and cotton that can be produced with available resources.", "q": "Identify two factors that limit production in Zambia.", "ans": ["Limited land", "Limited labour / labor"], "concept": "0455 Syllabus 1.1. Basic economic problem. Identification from source." },
  { "id": "2281_1b_S25_02", "case": "A cocoa farm in Ivory Coast employs 200 workers, uses tractors and irrigation equipment, and is run by an entrepreneur who bears the risk. The farm uses land that could otherwise grow rubber.", "q": "Identify two factors of production used on the cocoa farm.", "ans": ["Labour / labor / workers", "Capital / tractors / equipment"], "concept": "0455 Syllabus 1.2. Factors of production." },
  { "id": "2281_1b_S25_03", "case": "When the price of solar panels fell by 20% in Kenya, the quantity demanded increased by 35%. Households switched from generators to solar. The market cleared at the new lower price.", "q": "Identify two functions of the price mechanism mentioned in the case.", "ans": ["Rationing / allocate scarce resources", "Signalling / price signals scarcity"], "concept": "0455 Syllabus 2.1. Price mechanism." },
  { "id": "2281_1b_S25_04", "case": "In Germany, a trade union negotiated a 5% pay rise for factory workers. The union represents over 2 million members and uses collective bargaining. Membership has grown as workers seek better wages and conditions.", "q": "Identify two roles of the trade union.", "ans": ["Negotiate wages / pay rise", "Collective bargaining / represent workers"], "concept": "0455 Syllabus 3.1. Trade unions." },
  { "id": "2281_1b_S25_05", "case": "Two pharmaceutical companies merged in 2024. The merger was horizontal – both produced similar medicines. The new firm expected to cut costs by sharing research and marketing.", "q": "Identify two types of economies of scale the merger may create.", "ans": ["Marketing economies", "Research and development / R&D"], "concept": "0455 Syllabus 3.2. Firms – economies of scale." },
  { "id": "2281_1b_S25_06", "case": "The EU restricts imports of rice through an import quota. Only a fixed quantity can be imported each year. The aim is to protect European rice producers from foreign competition.", "q": "Identify two methods of trade protection.", "ans": ["Import quota", "Tariff / embargo"], "concept": "0455 Syllabus 6.2. Protection." },
  { "id": "2281_1b_S25_07", "case": "In the UK, a household is in relative poverty if its income is below 60% of the median. In 2023, about 14% were in this position. The World Bank defines absolute poverty as living on less than $2.15 a day.", "q": "Identify two measures of poverty.", "ans": ["Relative poverty / below median income", "Absolute poverty / poverty line"], "concept": "0455 Syllabus 5.2. Poverty." },
  { "id": "2281_1b_S25_08", "case": "Costa Rica's Human Development Index improved between 2015 and 2023. Life expectancy rose, average years of schooling increased, and GNI per capita grew. The HDI combines these three indicators.", "q": "Identify two components of the Human Development Index.", "ans": ["Life expectancy / health", "Education / years of schooling / GNI per capita"], "concept": "0455 Syllabus 5.1. HDI." },
  { "id": "2281_1b_S25_09", "case": "Nigeria has a young population with 43% under 15. The working-age population (15–64) supports these dependents. The government has focused on education to improve the future labour force.", "q": "Identify two groups that make up the dependent population.", "ans": ["Children / under 15", "Elderly / over 65"], "concept": "0455 Syllabus 5.3. Population structure." },
  { "id": "2281_1b_S25_10", "case": "Rwanda has promoted sustainable development. Projects use renewable energy and aim to protect forests. The government argues that growth must not damage the environment for future generations.", "q": "Identify two ways Rwanda is promoting sustainable development.", "ans": ["Renewable energy", "Protect forests / environment"], "concept": "0455 Syllabus 5.4. Sustainable development." },
  { "id": "2281_1b_S25_11", "case": "In 2024, the government of Portugal reduced income tax rates and increased spending on roads and hospitals. Tax revenue was expected to fall. The deficit was financed by borrowing.", "q": "Identify two fiscal policy measures used.", "ans": ["Reduce taxation / cut taxes", "Increase government spending"], "concept": "0455 Syllabus 4.3. Fiscal policy." },
  { "id": "2281_1b_S25_12", "case": "The government of Morocco set a maximum price for bottled cooking gas. Retailers cannot charge above this ceiling. The policy was introduced so that low-income families could afford this essential fuel.", "q": "Identify two reasons for setting a maximum price.", "ans": ["Reduce poverty / help poor", "Make essentials affordable"], "concept": "0455 Syllabus 2.3. Government intervention." },
  { "id": "2281_1b_S25_13", "case": "Malaysia introduced a minimum wage of 1,500 ringgit per month for workers in urban areas. The government argued that this would raise living standards for low-paid workers. Some employers said it would increase their costs.", "q": "Identify two effects of the minimum wage.", "ans": ["Raise wages / living standards", "Increase costs for firms / employers"], "concept": "0455 Syllabus 2.3. Minimum wage." },
  { "id": "2281_1b_S25_14", "case": "When Zambia's currency, the kwacha, was allowed to float freely, its value fluctuated against the US dollar. Exporters welcomed the flexibility but importers faced uncertainty over the cost of foreign goods.", "q": "Identify two characteristics of a floating exchange rate.", "ans": ["Value fluctuates / determined by market", "No central bank intervention"], "concept": "0455 Syllabus 6.3. Exchange rates." },
  { "id": "2281_1b_S25_15", "case": "Denmark's current account surplus grew in 2023. Earnings from exports of wind turbines and pharmaceuticals exceeded spending on imports. The country also received income from Danish firms' investments abroad.", "q": "Identify two components of the current account.", "ans": ["Balance of trade / exports minus imports", "Primary income / investment income"], "concept": "0455 Syllabus 6.1. Balance of payments." },
  { "id": "2281_1b_S25_16", "case": "The central bank of India raised interest rates in 2023 to reduce inflation. It also sold government bonds to reduce the money supply. Inflation had risen due to high consumer spending.", "q": "Identify two monetary policy tools used.", "ans": ["Raise interest rates", "Sell bonds / open market operations"], "concept": "0455 Syllabus 4.3. Monetary policy." },
  { "id": "2281_1b_S25_17", "case": "A Japanese car manufacturer opened a factory in Mexico, employing 3,000 local workers. The firm provided training in robotics. It also sourced parts from local suppliers. The factory exports cars to the US.", "q": "Identify two benefits the FDI brought to Mexico.", "ans": ["Jobs / employment", "Training / skills transfer / technology transfer"], "concept": "0455 Syllabus 6.4. FDI." },
  { "id": "2281_1b_S25_18", "case": "Colombia specialises in producing coffee and flowers. Farmers have gained expertise and the country has developed a reputation for quality. Colombia exports these products to many countries.", "q": "Identify two advantages of specialisation for Colombia.", "ans": ["Gain expertise / skills", "Gain reputation / quality"], "concept": "0455 Syllabus 1.4 / 6.1. Specialisation." },
  { "id": "2281_1b_S25_19", "case": "A cement plant in Pakistan emits dust that affects nearby villages. The government has imposed a tax on emissions and set limits on pollution. Firms must install filters or pay the tax.", "q": "Identify two ways the government is addressing pollution.", "ans": ["Tax on emissions / pollution tax", "Regulation / set limits"], "concept": "0455 Syllabus 2.3. Market failure – externalities." },
  { "id": "2281_1b_S25_20", "case": "Kenya has encouraged microfinance institutions to lend to small businesses. Banks have expanded mobile banking. Household savings have risen as more people can access secure accounts.", "q": "Identify two functions of the financial sector in Kenya.", "ans": ["Lending / provide loans", "Accept deposits / encourage saving"], "concept": "0455 Syllabus 5.4. Financial sector." }
];